import { TrendingUp, TrendingDown } from "lucide-react";

const MetricCard = ({ label, value, icon: Icon, trend, subValue }) => (
  <div className="group bg-white rounded-2xl p-2 sm:p-3 md:p-4 lg:p-5 shadow-sm border border-gray-100 hover:shadow-lg hover:border-blue-200 transition-all duration-300 hover:-translate-y-1 w-full">
    {/* Top Row */}
    <div className="flex items-start justify-between mb-1.5 sm:mb-2 md:mb-3">
      {/* Icon + Label */}
      <div className="flex items-center gap-1.5 sm:gap-2 md:gap-3">
        <div className="p-1 sm:p-1.5 md:p-2 bg-blue-50 rounded-xl group-hover:bg-blue-100 transition-colors">
          <Icon className="w-3.5 h-3.5 sm:w-4 sm:h-4 md:w-5 md:h-5 text-blue-600" />
        </div>
        <div className="text-[9px] sm:text-[11px] md:text-sm font-medium text-gray-500 uppercase tracking-wide">
          {label}
        </div>
      </div>

      {/* Trend */}
      {trend && (
        <div
          className={`flex items-center gap-1 text-[9px] sm:text-[11px] md:text-xs px-1.5 sm:px-2 py-0.5 sm:py-1 rounded-full ${
            trend > 0 ? "bg-green-50 text-green-600" : "bg-red-50 text-red-600"
          }`}
        >
          {trend > 0 ? (
            <TrendingUp className="w-2.5 h-2.5 sm:w-3 sm:h-3" />
          ) : (
            <TrendingDown className="w-2.5 h-2.5 sm:w-3 sm:h-3" />
          )}
          <span>{trend}%</span>
        </div>
      )}
    </div>

    {/* Value + SubValue */}
    <div className="space-y-0.5 sm:space-y-1">
      <div className="text-base sm:text-lg md:text-xl lg:text-2xl font-bold text-gray-900">
        {value}
      </div>
      {subValue && (
        <div className="text-[9px] sm:text-xs md:text-sm text-gray-500">
          {subValue}
        </div>
      )}
    </div>
  </div>
);

export default MetricCard;
